import{_ as i,o as a,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Defensive Lineup Builder","description":"","frontmatter":{},"headers":[],"relativePath":"lineup/defensive.md","filePath":"lineup/defensive.md"}'),n={name:"lineup/defensive.md"};function o(s,e,r,h,u,d){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="defensive-lineup-builder" tabindex="-1">Defensive Lineup Builder <a class="header-anchor" href="#defensive-lineup-builder" aria-label="Permalink to &quot;Defensive Lineup Builder&quot;">​</a></h1><p>The defensive lineup builder uses each player&#39;s fielding percentage at each position to suggest the strongest possible defensive alignment.</p><h2 id="how-positions-are-filled" tabindex="-1">How Positions Are Filled <a class="header-anchor" href="#how-positions-are-filled" aria-label="Permalink to &quot;How Positions Are Filled&quot;">​</a></h2><p>The algorithm fills positions in priority order: <strong>C → P → SS → 2B → 3B → 1B → CF → LF → RF</strong></p><p>This priority order reflects the defensive importance of each position. The best defenders go to the most demanding spots first.</p><p>For each position the algorithm selects the player with the highest FLD% who:</p><ul><li>Has played that position at least once this season</li><li>Is not already placed at another position</li><li>Is not marked as unavailable</li></ul><h2 id="overriding-the-suggestion" tabindex="-1">Overriding the Suggestion <a class="header-anchor" href="#overriding-the-suggestion" aria-label="Permalink to &quot;Overriding the Suggestion&quot;">​</a></h2><p>Tap any position to manually select a different player. Manual selections are <strong>locked</strong> — they are preserved when the lineup refreshes. Lock icon appears on locked positions.</p><p>To unlock a position and return it to the algorithm&#39;s suggestion tap the lock icon.</p><h2 id="availability-management" tabindex="-1">Availability Management <a class="header-anchor" href="#availability-management" aria-label="Permalink to &quot;Availability Management&quot;">​</a></h2><p>Before building a lineup mark unavailable players:</p><ol><li>Tap <strong>Manage Availability</strong></li><li>Tap each unavailable player and select a reason: <ul><li>Injury</li><li>Absent</li><li>Rest</li><li>Pitch count limit (set a count limit to automatically flag when threshold is reached)</li><li>Other</li></ul></li><li>Tap <strong>Done</strong></li></ol><p>Unavailable players appear grayed out and are excluded from suggestions.</p><h2 id="game-day-pitch-count-tracking" tabindex="-1">Game Day Pitch Count Tracking <a class="header-anchor" href="#game-day-pitch-count-tracking" aria-label="Permalink to &quot;Game Day Pitch Count Tracking&quot;">​</a></h2><p>The pitch count limit availability reason integrates with live game data. When a pitcher reaches their configured pitch count limit the app automatically flags them as unavailable in the lineup builder. This helps coaches comply with pitch count rules without manual tracking.</p><h2 id="minimum-data-requirements" tabindex="-1">Minimum Data Requirements <a class="header-anchor" href="#minimum-data-requirements" aria-label="Permalink to &quot;Minimum Data Requirements&quot;">​</a></h2><p>The defensive lineup builder works best with sufficient fielding data:</p><ul><li>Players with no fielding data at a position can still be placed manually</li><li>The algorithm only places players automatically at positions where they have logged fielding chances</li></ul><p>Early in a season the lineup builder may have limited data — build it manually until sufficient game data accumulates.</p>',20)])])}const m=i(n,[["render",o]]);export{c as __pageData,m as default};
